SELECT usr_no
  FROM users
 WHERE login_id = #{loginId}

SELECT balance
  FROM (
      SELECT balance
        FROM balances
       WHERE acnt_no = #{acntId}
         AND currency = #{curCd}
       ORDER BY upd_dt DESC, bal_no DESC
  )
 WHERE ROWNUM = 1

mapper.update:
UPDATE accounts_personal
   SET balance = #{balance}
 WHERE acnt_no = #{acntId}
